import{_ as a,o,c as s,a3 as l}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"61A. Personal Leave Pool","description":"","frontmatter":{"title":"61A. Personal Leave Pool","eba":"Nurses and Midwives 2024-2028","topics":["leave","personal-leave"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/61A-personal-leave-pool.md","filePath":"ebas/nurses-midwives/leave/61A-personal-leave-pool.md"}'),r={name:"ebas/nurses-midwives/leave/61A-personal-leave-pool.md"};function t(n,e,p,i,d,c){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="_61a-personal-leave-pool" tabindex="-1">61A. Personal Leave Pool <a class="header-anchor" href="#_61a-personal-leave-pool" aria-label="Permalink to &quot;61A. Personal Leave Pool&quot;">​</a></h1><p><strong>61A.1</strong> The Employer may establish a personal leave pool whereby eligible Employees have access, in defined situations, to additional paid personal leave hours that has been voluntarily donated to the pool by other Employees.</p><p><strong>61A.2</strong> Where this occurs, the Employer will publish criteria that defines the circumstances under which an Employer can (subject to the NES):</p><p><strong>(a)</strong> Donate accrued personal leave,</p><p><strong>(b)</strong> Access personal leave from the personal leave pool.</p><p><strong>61A.3</strong> A donation to a personal leave pool is irrevocable and the personal leave balance of the donating Employee under <a href="/eba/ebas/nurses-midwives/leave/61-personal-leave.html">clause 61</a> will be adjusted.</p><p>Plain language terms: sick leave pool, extra sick days, pooled personal leave.</p>',7)])])}const m=a(r,[["render",t]]);export{h as __pageData,m as default};
